kernel void BFS_1(
    const Node* graph_nodes,
    const int* graph_edges,
    char* graph_mask,
    char* updating_graph_mask,
    const char* graph_visited,
    int* cost,
    const int no_of_nodes
) {
    int tid = get_global_id(0);

    if (tid >= no_of_nodes) return;

    if (graph_mask[tid] == 1) {
        graph_mask[tid] = 0;
        int start = graph_nodes[tid].starting;
        int end = start + graph_nodes[tid].no_of_edges;

        for (int i = start; i < end; i++) {
            int id = graph_edges[i];
            if (graph_visited[id] == 0) {
                cost[id] = cost[tid] + 1;
                updating_graph_mask[id] = 1;
            }
        }
    }
}

kernel void BFS_2(
    char* graph_mask,
    char* updating_graph_mask,
    char* graph_visited,
    char* over,
    const int no_of_nodes
) {
    int tid = get_global_id(0);

    if (tid >= no_of_nodes) return;

    if (updating_graph_mask[tid] == 1) {
        graph_mask[tid] = 1;
        graph_visited[tid] = 1;
        *over = 1;
        updating_graph_mask[tid] = 0;
    }
}
